INSERT INTO `sys_campus_knowledge` (`type_id`, `title`, `content`, `file_url`, `status`, `create_by`, `create_time`, `update_time`) VALUES
(1, '本科生毕业设计（论文）工作规范', '为加强本科生毕业设计（论文）工作的规范化管理，提高毕业论文质量，培养学生综合运用所学知识解决实际问题的能力，特制定本规范。\n\n**一、选题要求**\n1. 选题应符合专业培养目标，体现综合训练基本要求。\n2. 题目难易度适当，具有可行性，原则上每人一题。\n3. 鼓励结合生产实际、科学研究及社会热点问题的选题。\n\n**二、开题报告**\n学生需在广泛查阅文献的基础上撰写开题报告，包含研究目的与意义、国内外研究现状、研究内容与方法、进度安排等。开题未通过者需在一周内修改重新开题。\n\n**三、论文撰写**\n严格按照学校规定的格式模板（包括标题、摘要、关键词、正文、参考文献等）进行撰写，正文字数理工科一般不少于8000字，文科不少于10000字。\n\n**四、查重与答辩**\n1. 所有毕业论文均需进行学术不端检测，文字复制比（查重率）不得超过30%。\n2. 答辩采用PPT汇报形式，个人陈述10-15分钟，专家提问5-10分钟。\n3. 答辩未通过者，根据评定结果进行重大修改（二辩）或延期毕业。', NULL, '1', '', NOW(), NOW()),
(1, '学生转专业实施细则', '为充分尊重学生个性发展，激发学习主动性和积极性，规范校内转专业工作，结合学校实际，制定本细则。\n\n**一、申请资格**\n1. 我校全日制在籍一年级或二年级本科生。\n2. 第一学期或第一学年所有必修课成绩合格（无挂科记录），且综合绩点排名原则上在本专业前30%以内。\n3. 身体条件符合转入专业招生要求。\n\n**二、不得转专业的情形**\n1. 以特殊招生形式（如艺术类、体育类、高水平运动员等）录取的学生。\n2. 正在休学、保留学籍或达到退学条件的学生。\n3. 已有转专业或转学经历的学生。\n\n**三、办理流程与时间**\n1. 每年4月或10月，各学院公布拟接收名额与考核方案。\n2. 学生登录教务系统填写转专业申请，并提交成绩单及个人陈述。\n3. 转入学院组织笔试或面试考核（择优录取）。\n4. 教务处公示拟批准名单（公示期5天）。\n5. 公示无异议后，办理学籍变动手续，并完成新专业培养方案的学分认定。', NULL, '1', '', NOW(), NOW()),
(1, '课程补考与重修管理规定', '关于课程考核未通过学生的后续学业管理，具体规定如下：\n\n**一、补考规定**\n1. 课程总评成绩在45分（含）至59分（含）之间者，可参加一次学期初的补考。\n2. 补考时间一般为下一学期开学后第2-3周。\n3. 补考成绩按卷面实际得分记载，但最高不超过70分，并注明“补考”字样。\n4. 缺考、作弊及总评成绩低于45分的课程，无补考资格，必须重修。\n\n**二、重修规定**\n1. 学生可自主选择跟班重修或参加周末开设的重修班。\n2. 每学期重修课程原则上不超过3门。\n3. 重修需按学分缴纳重修费（标准为100元/学分）。\n4. 重修课程与正常课程考核方式一致，成绩按实际考核分数录入，不设上限。\n\n**三、注意事项**\n学生在校期间，同一门课程重修次数不得超过两次。若两次重修仍不合格，结业后一年内可申请返校再次重修，合格者换发毕业证书。', NULL, '1', '', NOW(), NOW()),
(1, '校园商用服务与商户管理规定', '为维护校园正常秩序，保障师生合法权益，对校园内所有商铺、服务网点进行统一规范管理：\n\n**一、经营管理**\n1. 校内商铺必须持有效《营业执照》和《食品经营许可证》（餐饮类）亮证经营。\n2. 所有商品必须明码标价，价格不得明显高于校外同类商品市场均价。\n3. 严禁向学生出售烟酒（尤其是未成年人）、管制刀具及含有暴力色情内容的出版物。\n\n**二、食品安全**\n1. 超市及便利店不得销售“三无”食品、过期变质食品。\n2. 奶茶店、面包房等自制食品需公示添加剂使用情况。\n3. 学校后勤集团每月组织一次商户食品安全突击检查。\n\n**三、投诉与处罚**\n1. 师生可通过“智慧后勤”APP或电话12345进行投诉。\n2. 一经查实有价格欺诈、售卖假货等行为，商户需“退一赔三”，并扣除履约保证金1000元。\n3. 一个季度内累计有效投诉超过5次，学校有权单方面解除租赁合同。', NULL, '1', '', NOW(), NOW()),
(2, '学生证及火车票优惠卡补办流程', '学生证是证明在校身份的重要证件，火车票学生优惠卡是购买优惠火车票的凭证。如果不慎遗失，请按以下流程及时补办：\n\n**一、挂失准备**\n1. 发现丢失后，第一时间通过“校园信息门户”或“学工系统”进行线上挂失，防止被他人冒用。\n2. 如学生证被冒用造成学校财产损失或声誉影响，原持证人需配合处理。\n\n**二、线上申请与缴费**\n1. 登录“学工一体化平台” -> “学生证补办”模块。\n2. 填写补办理由，上传电子版证件照（蓝底或白底，像素不低于300dpi）。\n3. 缴纳工本费：学生证10元/本，火车票优惠卡7元/张。\n\n**三、现场办理与领取**\n1. 提交申请后，于每周三下午（14:00-17:00）携带身份证前往学生事务大厅（综合楼一楼）办理。\n2. 现场制证，当场领取，如需修改乘车区间（家庭地址变更），需提供父母工作地居住证或暂住证复印件。\n3. 新补办的学生证需重新注册（按学期加盖注册章），火车票优惠卡需重新充磁（每年可享4次优惠）。', NULL, '1', '', NOW(), NOW()),
(2, '在读证明及成绩单自助打印流程', '为方便学生求职、考研、出国或办理其他业务，学校提供“一站式”自助打印服务，具体流程如下：\n\n**一、服务终端位置**\n1. 主校区：学生事务大厅（24小时开放）、图书馆二楼大厅。\n2. 东校区：综合教学楼一楼大厅。\n3. 北校区：行政楼一楼大厅。\n\n**二、打印步骤**\n1. 使用校园卡刷卡登录，或输入教务系统账号密码登录。\n2. 在主界面选择所需项目：\n   - 中文在读证明（免费，首份免费，第二份起2元/份）\n   - 中文成绩单（免费，首份免费，第二份起5元/份）\n   - 英文在读证明（10元/份，含翻译）\n   - 英文成绩单（15元/份，含翻译及绩点换算说明）\n3. 确认信息无误后，点击“打印”，系统自动盖章（带防伪二维码）。\n\n**三、注意事项**\n1. 成绩单显示所有已修读课程，挂科或补考记录会保留（补考成绩后标注“补考”）。\n2. 如对成绩有异议，需先联系所在学院教务秘书核实，再由教务处修正系统数据。\n3. 自助打印机故障或需办理封装（信封密封盖章），请联系学生事务大厅工作人员。', NULL, '1', '', NOW(), NOW()),
(2, '毕业生离校手续办理全流程', '毕业生在离校前需办理各项离校手续，结清费用、归还借阅物品，方可领取毕业证及学位证。请按以下步骤操作：\n\n**一、线上离校系统办理（6月上旬启动）**\n1. 登录“离校管理系统”，查看各部门审核状态（财务处、图书馆、宿管中心、教材科等）。\n2. 如有未办结项，需线下处理并等待相关单位在系统内确认通过。\n\n**二、线下必要环节**\n1. **财务结算**：结清学费、住宿费、教材费，多缴费用将统一退还至学生银行卡。\n2. **图书馆清欠**：还清所有借阅图书，结清逾期滞纳金或丢书赔款。\n3. **宿舍退宿**：清理个人物品，归还宿舍钥匙、空调遥控器，验收家具设施。经宿管员查验确认无损坏后，开具《退宿证明》。\n4. **户口迁移**：入学时将户口迁至学校的毕业生，需到保卫处办理户口迁移证。\n\n**三、证书领取**\n1. 所有离校环节均办理完毕后，持本人身份证和《退宿证明》到所在学院学工办领取《毕业证》和《学位证》。\n2. 委托他人代领的，需提供双方身份证复印件及本人手写签名的授权委托书。\n3. 未在规定时间内办结离校手续的学生，证书将暂存学院，最长保管期为一学年，逾期未领取按相关规定处理。', NULL, '1', '', NOW(), NOW()),
(2, '校园网账号开通、维护及密码找回指南', '校园网是师生在校学习、科研、生活的重要基础设施，为确保安全顺畅使用，请遵守以下指南：\n\n**一、账号开通与资费**\n1. 新生入学后，学校统一开通校园网账号，账号格式为“学号”，初始密码为“身份证号后六位”。\n2. 资费标准：\n   - 基础套餐：每月30元，包含80GB国内流量+校园网不限流量。\n   - 高级套餐：每月60元，包含200GB国内流量+校园网不限流量。\n   - 国际加速包：每月10元，用于访问境外学术数据库（Web of Science、IEEE等）。\n3. 缴费方式：通过“校园卡APP” -> “网络缴费” 或 前往网络与信息中心前台。\n\n**二、密码找回与修改**\n1. **自助重置**：访问校园网自助服务网站（`selfnet.zhihuitong.edu.cn`），点击“忘记密码”，通过绑定手机号或邮箱验证重置。\n2. **线下办理**：如无法自助找回，本人携带学生证或身份证到网络与信息中心（主楼C座104）重置密码。\n3. **安全提示**：请勿将账号借给他人使用，也不要用生日、123456等弱口令。定期修改密码（建议每90天修改一次）。\n\n**三、常见故障处理**\n1. 无法连接WiFi：先尝试“忘记网络”后重新连接，或重启设备。\n2. 认证失败：检查是否欠费或账号被锁定（密码错误超过10次会锁定30分钟）。\n3. 网速慢或断流：避开高峰期（19:00-23:00），或使用网线连接宿舍有线端口。\n4. 报修渠道：拨打服务热线 022-12345678 或 在“掌上校园”APP提交网络故障工单。', NULL, '1', '', NOW(), NOW()),
(2, '教室/活动场地及报告厅借用申请流程', '为合理调配教学资源，凡校内单位、学生社团或正式注册的团队借用教室、活动场地或报告厅，需履行以下借用手续：\n\n**一、借用类别与权限**\n1. 普通教室：用于班会、自习、社团内部培训等非教学活动，由教务处教务科审批。\n2. 多媒体教室：包含投影、音响、电脑等设备，需提前测试设备兼容性，由现代教育技术中心审批。\n3. 报告厅/礼堂：用于大型讲座、文艺汇演、颁奖典礼等，由校团委或校长办公室审批。\n4. 体育场馆：用于体育比赛、运动会、集体锻炼，由体育教学部审批。\n\n**二、借用流程（OA系统）**\n1. 申请人提前3-7天登录“OA办公系统” -> “会议室/场馆预约”模块。\n2. 填写借用信息：场地名称、使用时间段（精确到小时）、活动内容、预计人数、是否需要特殊设备（如麦克风、投影仪）。\n3. 上传《活动安全责任承诺书》（大型活动需提交安保预案）。\n4. 依次由指导老师（社团用）、部门负责人、场地管理部门审批。\n5. 审批通过后，系统生成《场地使用单》，使用当天需向物业管理人员出示该单据。\n\n**三、使用规范**\n1. 严禁在教室内用餐、吸烟、粘贴横幅或使用双面胶。\n2. 活动结束后关闭电灯、空调、投影仪，清理垃圾，桌椅恢复原位。\n3. 超时使用需重新申请，不得擅自延长时间或转借给校外人员。\n4. 损坏设施按原价赔偿，并视情节严重程度予以通报批评。', NULL, '1', '', NOW(), NOW()),
(2, '学生宿舍空调租赁及日常报修流程', '为确保学生宿舍空调正常使用，创造舒适的学习生活环境，学校与第三方租赁公司合作提供空调服务，具体规定如下：\n\n**一、租赁办理**\n1. 租赁主体：以宿舍为单位统一办理，舍长负责签约及费用缴纳。\n2. **租赁费用**：\n   - 按学年租赁：400元/学年·间（含安装、维修、拆机费用，不含电费）。\n   - 按学期租赁：240元/学期·间（不推荐，暑假或寒假需搬离）。\n3. 办理地点：开学期间在宿舍楼一楼大厅设临时服务点，日常可至“学生社区服务中心”或在线签约（微信小程序“xx校园服务”）。\n\n**二、使用规范**\n1. 空调专用插座不得接插排或大功率电器（电暖气、电热毯等）。\n2. 夏季制冷设定温度不低于26℃，冬季制热不高于20℃，节约用电。\n3. 离开宿舍时必须关闭空调，禁止长时间空转。\n\n**三、报修流程**\n1. 空调出现故障（不制冷/热、漏水、异响等），首先检查遥控器电池和设置模式是否正确。\n2. 关注微信小程序“XX校园报修” -> 选择“空调报修” -> 填写宿舍号、故障现象、联系电话。\n3. 上传故障视频或照片，便于维修人员判断问题。\n4. 维修人员一般24小时内上门（高峰期可能延长至48小时），请保持手机畅通。\n5. 轻微故障（缺氟、清扫滤网）免费维修；人为损坏（摔坏遥控器、外壳破损）按维修成本价赔偿。', NULL, '1', '', NOW(), NOW()),
(3, '校园交通安全与电动车管理规定', '为维护校园交通秩序，预防和减少校园交通事故，保障师生人身安全，对校园内机动车及非机动车管理作如下规定：\n\n**一、机动车管理**\n1. 教职工车辆凭“校园车辆通行证”进出校园，时速不得超过20公里/小时。\n2. 外来车辆入校需提前通过“智慧访客系统”预约，或由校内对接单位向保卫处报备。\n3. 车辆必须停放在划定的停车场或停车线内，严禁占用消防通道、人行道、绿化带。\n4. 教学楼、宿舍楼、食堂门前路段禁止长时间停车（即停即走，限时3分钟）。\n\n**二、电动车管理**\n1. 所有电动车必须悬挂公安机关核发的正式号牌，**无牌电动车不得入校**。\n2. 骑行电动车须佩戴安全头盔，后座不得搭载12周岁以上人员。\n3. 电动车在校园内限速15公里/小时，严禁逆向行驶、单手骑车、看手机。\n4. 充电必须在指定的智能充电桩进行（宿舍楼后、地下车库），严禁在宿舍、教学楼、实验楼内充电或飞线充电，违者没收充电器并通报批评。\n\n**三、违规处理**\n1. 违反上述规定，一次警告、二次锁车并通报所在学院、三次取消车辆入校资格。\n2. 因违章造成交通事故或人身伤害的，移交公安机关处理，并追究相关责任。', NULL, '1', '', NOW(), NOW()),
(3, '实验室安全准入与日常行为准则', '为保障实验教学及科研工作安全有序开展，防止实验室意外事故，全体师生必须遵守以下安全准则：\n\n**一、安全准入制度**\n1. 所有本科生、研究生在进入实验室前，必须完成“实验室安全知识线上学习平台”的课程学习与考试，成绩达到90分以上方可获得准入资格。\n2. 考试不合格可重考，但最多不超过3次。\n3. 进入特殊类别实验室（化学类、生物类、辐射类）还需额外参加专项安全培训。\n\n**二、日常行为规范**\n1. 实验服：进入实验室必须穿着实验服，长发束起，不得穿拖鞋、短裤、裙子。\n2. 个人防护：进行有腐蚀性、刺激性或毒性实验时，必须佩戴护目镜、手套和口罩。\n3. 试剂管理：所有试剂瓶必须有清晰标签（名称、浓度、配制日期、配制人）。\n4. 废弃物处理：实验废物必须分类倒入指定容器（有机废液、无机废液、尖锐物、固体废物），严禁倒入下水道或普通垃圾桶。\n5. 仪器操作：严格按照仪器操作规程进行，不得擅自改装或拆卸。大型精密仪器使用前需登记。\n\n**三、应急处理**\n1. 发生化学品泄漏，立即疏散并上报实验室管理员，根据化学品性质进行中和或吸附处理。\n2. 发生烧伤或割伤，立即用大量清水冲洗，前往校医院或拨打120。\n3. 发现火情，立即关闭电源、气源，使用灭火器扑救，并拨打校内报警电话 1234。\n4. 实验结束时务必断水断电，关好门窗。', NULL, '1', '', NOW(), NOW()),
(3, '学生勤工助学与校外兼职行为规范', '为培养学生劳动观念和社会实践能力，规范勤工助学及校外兼职活动，提出以下行为准则：\n\n**一、校内勤工助学**\n1. 学生可申请学校提供的校内助学岗位（如图书馆理书员、实验室助理、行政助理等），薪酬标准为15元/小时，每月不超过40小时。\n2. 申请流程：登录“学工系统” -> “勤工助学” -> 查看岗位列表 -> 填写申请并参加面试。\n3. 在岗期间必须认真负责，不得迟到早退，遵守所在部门的劳动纪律。\n\n**二、校外兼职**\n1. 学生在不影响学业的前提下可适度从事校外兼职（如家教、公司实习、服务员等）。\n2. **禁止从事**的活动：\n   - 以学校名义进行商业推广或招生代理。\n   - 参与网络刷单、刷信誉、贷款刷业绩等非法或灰色产业。\n   - 进入酒吧、KTV、夜总会等娱乐场所工作。\n3. **安全提示**：\n   - 务必与用人单位签订书面《劳务协议》，明确工作内容、时长、薪酬及结算方式。\n   - 警惕“先交押金、押身份证、高薪诱惑”等求职陷阱。\n   - 兼职期间注意人身财产安全，告知室友或家人工作地点及返回时间。\n\n**三、违规与处理**\n1. 因校外兼职导致旷课、迟到、成绩严重下滑者，辅导员将约谈并劝其停止兼职，屡教不改者按学籍管理规定处理。\n2. 利用校园资源进行营利性活动或发布虚假招聘信息欺诈同学的，视情节给予警告及以上处分。', NULL, '1', '', NOW(), NOW()),
(3, '学生宿舍文明卫生及安全管理细则', '为了营造一个整洁、舒适、安全的住宿环境，特制定本管理细则，请全体住宿生严格遵守：\n\n**一、卫生要求**\n1. 每个宿舍建立卫生值日表，每日清扫地面，每周进行一次大扫除（擦窗台、清死角）。\n2. 桌面物品摆放整齐，床铺平整，被子叠放规范，床下鞋子不多于4双且摆放整齐。\n3. 卫生间无异味，便池无黄垢，洗手台无积水。\n4. 宿舍门口及楼道不准堆放垃圾或杂物，垃圾袋装化后带至楼下集中垃圾箱。\n\n**二、安全与秩序**\n1. **严禁使用**：热得快、电热毯、电煮锅、电暖器、电卷棒等发热类大功率电器，宿舍总功率不得超过800W。\n2. **严禁存放**：酒精炉、煤油炉、管制刀具（刀刃超过10cm）、易燃易爆品（鞭炮、汽油）、宠物（猫、狗、仓鼠、鸟类等）。\n3. 严禁留宿异性或校外人员。未经宿管中心批准，不得擅自调换床位或宿舍。\n4. 晚上23:00前必须返回宿舍。晚归者需在前台登记并说明原因，累计晚归3次或夜不归宿1次，将通报至学院学工办。\n\n**三、检查与奖惩**\n1. 宿管员每月组织2次卫生与安全检查，评分结果在宿舍楼内公示栏公布。\n2. 学期末，评选“文明宿舍”并给予一定物质奖励及综测加分。\n3. 脏乱差或违规电器被查获的宿舍，取消该宿舍全体成员当年评优评先资格，责任人按学生违纪处分条例处理。', NULL, '1', '', NOW(), NOW()),
(4, '关于2024-2025学年第一学期选课安排的通知', '各学院、各年级同学：\n\n2024-2025学年第一学期选课工作即将开始，为确保选课顺利进行，现将有关事项通知如下：\n\n**一、选课时间**\n- **第一轮（初选）**：2024年6月10日 09:00 — 6月16日 23:59 （不限容量，抽签决定）\n- **第二轮（正选）**：2024年6月20日 09:00 — 6月27日 23:59 （先到先得）\n- **第三轮（补退选）**：2024年9月2日 09:00 — 9月8日 23:59 （开学第一周）\n\n**二、选课网址**\n登录“教务处信息服务平台” `http://jw.zhihuitong.edu.cn`，使用学号和密码登录。\n\n**三、注意事项**\n1. 请提前核对本人培养方案，确认应修读的通识选修课、专业选修课类别及学分要求。\n2. 每学期选修总学分不得超过30学分（毕业班除外）。\n3. 第一轮选课不分先后，结束后系统随机筛选中签名单，请勿扎堆选课。\n4. 第二轮选课逾期不再补选，未完成选课者将影响后续参加课程学习及考试。\n5. 选课结束后，务必登录系统查看“我的课表”，并以此为准上课。\n\n请同学们相互转告，按时选课。如有问题，请联系教务处运行科：022-1234567。', NULL, '1', '', NOW(), NOW()),
(4, '关于申报2024年度国家奖学金及天津市人民政府奖学金的通知', '各学院：\n\n根据教育部及市教委相关文件精神，现启动2024年度国家奖学金及天津市人民政府奖学金评定工作，具体事宜通知如下：\n\n**一、奖励标准及名额**\n- 国家奖学金：8000元/人·年，全校共42名。\n- 天津市人民政府奖学金：8000元/人·年，全校共28名。\n\n**二、申请条件**\n1. 我校全日制在籍二年级（含）以上本科生。\n2. 热爱社会主义祖国，拥护党的领导，遵守宪法和法律，遵守学校规章制度。\n3. 诚实守信，道德品质优良，无违纪处分记录。\n4. **学习要求**：上一学年各门课程成绩均在80分以上，且综合测评成绩排名与学习成绩排名均位于专业前10%。\n5. 对于排名在10%-30%之间的学生，如在道德风尚、学术研究、学科竞赛、创新发明、社会实践、体育竞赛、文艺比赛等某一方面表现特别优秀，也可申请。\n\n**三、申请流程与时间节点（暂定）**\n1. **个人申请**（9月15日-9月22日）：学生登录“学工系统”填写《国家奖学金申请审批表》，并提交获奖证书复印件及成绩单。\n2. **学院初评**（9月23日-9月30日）：学院评审小组对申请人进行资格审查和答辩评审，确定拟推荐名单并公示5个工作日。\n3. **学校审定**（10月8日-10月15日）：学校评审委员会对各学院推荐人选进行评审，确定最终名单，全校公示5天。\n4. **表彰发放**：公示无异议后，报上级部门审批，12月底前将奖学金一次性发放至学生银行卡，并颁发荣誉证书。\n\n**四、其他说明**\n1. 同一学年内，国家奖学金、天津市人民政府奖学金、国家励志奖学金不可兼得。\n2. 申请材料弄虚作假者，一经查实，取消资格并给予相应纪律处分。\n\n联系人：张老师 联系电话：022-7654321', NULL, '1', '', NOW(), NOW()),
(4, '关于防范电信网络诈骗的紧急安全提示', '全体师生员工：\n\n近期，电信网络诈骗案件呈多发态势，不法分子针对大学生群体冒充公检法、电商客服、学校老师等身份实施诈骗。为切实保障广大师生的财产安全，保卫处发布紧急安全提示：\n\n**一、常见诈骗类型**\n1. **冒充客服退款类**：谎称网购商品质量问题或快递丢失，以“退款”或“理赔”为名，诱导你点击钓鱼链接或提供短信验证码。\n2. **刷单返利类**：以“足不出户、日进斗金”为诱饵，先给少量返利，后以“联单”“卡单”为由拒绝返款并拉黑。\n3. **冒充熟人类**：盗取QQ或微信，冒充同学、老师、亲戚，以“生病急用钱”“交报名费”等理由要求转账。\n4. **虚假贷款类**：以“无抵押、低利息、秒到账”为诱饵，称你卡号填写错误要求缴纳“解冻费”或“保证金”。\n5. **杀猪盘（交友诱导投资）**：在婚恋或社交平台伪装成高富帅、白富美，建立感情后诱导参与虚假投资理财或赌博。\n\n**二、防范要点（四个“凡是”）**\n1. 凡是陌生人要求转账、汇款、提供验证码的，**都是诈骗**。\n2. 凡是声称“注销校园贷”否则影响征信的，**都是诈骗**。\n3. 凡是通知“家属”出事要先汇款的，**都是诈骗**。\n4. 凡是自称领导、老师要求转账到“安全账户”的，**都是诈骗**。\n\n**三、求助渠道**\n1. 全国反诈专线：**96110**（来电务必接听）。\n2. 保卫处报警电话：**022-12345678**（24小时）。\n3. 下载“国家反诈中心”APP，实名注册并开启来电预警功能。\n\n请各学院、各部门加强反诈宣传教育，提醒师生员工不轻信、不转账、不透露。', NULL, '1', '', NOW(), NOW()),
(4, '关于评选2023-2024学年“优秀学生干部”及“先进班集体”的通知', '各学院学工办：\n\n为树立先进典型，激励广大学生德智体美劳全面发展，加强班集体建设，学校决定开展2023-2024学年“优秀学生干部”及“先进班集体”评选工作。现将有关事宜通知如下：\n\n**一、评选对象**\n1. 优秀学生干部：全日制二年级（含）以上本科生中担任班委、党支部委员、团支委、院（校）学生会干部等职务满一年的学生。\n2. 先进班集体：全校二年级（含）以上自然班。\n\n**二、评选条件**\n**（一）优秀学生干部**\n1. 理想信念坚定，拥护党的领导，积极践行社会主义核心价值观。\n2. 学习态度端正，刻苦努力，上一学年综合测评成绩排名在专业前50%，无补考或重修课程。\n3. 热心服务同学，工作积极主动，有较强的组织协调能力，在同学中有较高威信。\n4. 积极参加社会实践、志愿服务和文体活动，身心健康。\n\n**（二）先进班集体**\n1. 班委会、团支部团结协作，班风积极向上，班级制度健全。\n2. 班级学风优良，不及格率低，英语四六级通过率高，无考试作弊行为。\n3. 班级成员遵纪守法，一学年内无人受到违纪处分。\n4. 积极开展主题班会、团日活动及文体活动，班级凝聚力强。\n\n**三、评选程序**\n1. **申报阶段**（11月1日-11月10日）：符合条件的个人或集体填写申报表，并附事迹材料（不少于1000字）及佐证材料，提交至学院学工办。\n2. **学院初评**（11月11日-11月20日）：学院召开评选会议，确定推荐名单，并在学院内公示3个工作日。\n3. **学校评审**（11月21日-11月30日）：学生处对推荐材料进行审核，组织校级评审答辩（先进班集体需PPT展示），确定最终名单。\n4. **表彰宣传**（12月上旬）：发文表彰，颁发荣誉证书及奖金（优秀学生干部500元/人，先进班集体1000元/班），并通过橱窗、校园网宣传先进事迹。\n\n请各学院高度重视，严格按照条件与程序，公开、公平、公正地做好评选推荐工作。', NULL, '1', '', NOW(), NOW()),
(2, '大学生城镇居民医疗保险（医保）报销指南', '为保障学生基本医疗需求，减轻医疗费用负担，我校学生统一参加天津市城乡居民基本医疗保险。现将报销相关事宜说明如下：\n\n**一、参保范围与缴费**\n1. 全体全日制本专科生、研究生。\n2. 每年9月至12月为集中参保缴费期，医保待遇享受期为次年1月1日至12月31日。\n3. 缴费标准：每人每年250元（困难学生、残疾学生减免）。\n\n**二、报销范围与比例**\n1. **门诊（普通门急诊）**：\n   - 仅限校医院或转诊至定点医院（天津医科大学总医院、天津医院等）。\n   - 起付线：500元/年，报销比例50%，年度封顶线4000元。\n2. **住院**：\n   - 一级医院：起付线300元，报销比例80%。\n   - 二级医院：起付线600元，报销比例70%。\n   - 三级医院：起付线900元，报销比例60%。\n   - 年度封顶线18万元。\n3. **门诊大病（恶性肿瘤放化疗、肾透析、器官移植抗排异等）**：\n   - 起付线500元，报销比例65%，与住院共用年度封顶线。\n\n**三、报销流程**\n1. **校医院就诊**：直接刷医保电子凭证或社保卡结算，个人仅支付自费部分。\n2. **转诊或急诊外院就诊**：\n   - 全额垫付医疗费用。\n   - 准备材料：身份证/社保卡复印件、诊断证明（加盖医院公章）、费用清单、发票原件、转诊证明（急诊不需要）。\n   - 每月1-10日（工作日）将材料提交至校医院医保办公室。\n   - 学校统一向医保局申报，报销金额约1-2个月打入学生银行卡。\n\n**四、注意事项**\n1. 非定点医院、美容整形、牙科修复（种牙、正畸）、自购药品不予报销。\n2. 商业保险可作为补充报销，先报医保，再用商保报销剩余部分。\n3. 寒暑假或实习期间在外地就医，需先备案，回校后提交材料报销，报销比例降低10%。\n4. 医保政策每年可能微调，请关注“校医院”微信公众号获取最新通知。', NULL, '1', '', NOW(), NOW()),
(4, '关于举行2024年田径运动会及停课安排的通知', '各学院、各部门：\n\n为全面贯彻党的教育方针，推动全民健身运动，增强师生体质，经学校研究决定，于2024年5月17日-18日（星期五、星期六）举行校田径运动会。现将有关事项通知如下：\n\n**一、时间与地点**\n1. 时间：2024年5月17日 08:00 开幕式，5月18日 16:30 闭幕式。\n2. 地点：主校区体育场。\n\n**二、停课安排**\n1. 5月17日（星期五）全校本科生、研究生**停课一天**。\n2. 所停课程由任课教师自行安排时间补课或调整教学进度。\n\n**三、开幕式要求**\n1. 各学院需组织学生方队入场，方队人数不少于60人，服装统一，精神饱满。\n2. 5月17日上午07:30前，各学院方队在指定地点集合完毕。\n3. 参加广播体操表演及团体操表演的学生按体育教学部统一安排提前彩排。\n\n**四、观赛与纪律**\n1. 运动会期间，各学院需组织本学院学生在看台指定区域就座观赛，做好考勤工作，不得无故缺席。\n2. 严禁非参赛人员进入比赛场地，服从裁判员及工作人员管理。\n3. 文明观赛，不得喝倒彩、乱扔垃圾，保持看台卫生。\n\n**五、安全与后勤**\n1. 参赛运动员赛前进行体检，身体不适者请勿参赛。\n2. 现场设医疗保障点（体育场西门），备有急救药品及器械。\n3. 如遇恶劣天气，运动会推迟举行，届时另行通知。\n\n请各单位认真做好组织工作，确保运动会安全、有序、精彩、圆满。', NULL, '1', '', NOW(), NOW()),
(3, '学生文明上网及网络言行规范', '为净化网络环境，维护校园网络秩序，倡导文明上网，根据《中华人民共和国网络安全法》及学校相关管理规定，特制定本规范：\n\n**一、使用校园网**\n1. 严禁利用校园网络从事攻击、侵入他人计算机系统，或制作、传播计算机病毒等破坏性程序。\n2. 严禁私自架设代理服务器、VPN或Wi-Fi热点（宿舍有线网络转无线）。\n3. 不得盗用他人IP地址、账号密码。\n\n**二、网络言行**\n1. **严禁传播**：捏造或歪曲事实、散布虚假信息、制造校园恐慌的言论。\n2. **严禁发布**：淫秽、色情、赌博、暴力、凶杀、恐怖或教唆犯罪的信息。\n3. **严禁侮辱**：公然侮辱他人或者捏造事实诽谤他人、老师、学校，侵害他人名誉权、隐私权。\n4. **谨慎发言**：在社交平台（微博、抖音、小红书、朋友圈）发布与学校相关的内容时，不应泄露国家秘密或学校科研机密。\n\n**三、违规与处理**\n1. 情节轻微的，由学院或辅导员进行批评教育。\n2. 情节较重，造成不良影响的，依据《学生违纪处分条例》给予警告至记过处分。\n3. 情节严重，违反国家法律法规的，移交公安机关处理，学校给予开除学籍处分。\n\n网络空间不是法外之地，请各位同学文明上网、理性发声，共同维护清朗的网络空间。', NULL, '1', '', NOW(), NOW()),
(1, '本科生辅修专业及辅修学士学位管理办法', '为鼓励学有余力的学生拓展知识面，培养复合型人才，学校推行辅修专业及辅修学士学位制度，具体管理办法如下：\n\n**一、申请条件**\n1. 我校全日制在籍一年级或二年级本科生。\n2. 主修专业已修读课程全部合格，且综合绩点不低于2.5（或平均分75分以上）。\n3. 申请攻读辅修学士学位的学生，主修专业与辅修专业应分属不同学科门类。\n\n**二、教学与学分**\n1. 辅修专业总学分一般为40-50学分，辅修学士学位总学分为50-60学分（含毕业设计/论文）。\n2. 上课时间一般安排在周末、晚间或暑假小学期。\n3. 辅修课程成绩单独记载，不及格可补考或重修。\n\n**三、证书与学位**\n1. 完成辅修专业培养方案规定的全部课程且成绩合格，颁发**辅修专业证书**（不另授学位）。\n2. 完成辅修学士学位培养方案（含毕业设计/论文），且主修专业获得学士学位者，颁发**辅修学士学位证书**（在学位证上注明）。\n3. 主修专业未能毕业者，无论是否完成辅修学业，均不颁发辅修证书或学位。\n\n**四、收费与流程**\n1. 按学分收费，标准为120元/学分。\n2. 申请流程：每学期第12-14周，登录教务系统填报辅修志愿 -> 辅修学院审核 -> 教务处备案 -> 缴纳学费 -> 选课修读。', NULL, '1', '', NOW(), NOW()),
(2, '学生违纪处分申诉与撤销流程', '为保障学生合法权益，确保处分决定公正、公平，凡对学校做出的违纪处分决定有异议的学生，可按以下流程提出申诉或申请撤销处分：\n\n**一、处分申诉流程（收到处分决定书后10个工作日内）**\n1. 学生本人填写《学生违纪处分申诉表》（可在学生处网站下载），陈述申诉理由并附上相关证据材料。\n2. 将申诉表提交至所在学院学工办，学院在3个工作日内签署意见。\n3. 学生处（或研究生院）受理申诉，并成立学生申诉处理委员会。\n4. 委员会在接到申诉书后15个工作日内进行复查，并做出复查结论。\n5. 复查结论分为：维持原处分决定、撤销处分决定或变更处分决定。\n6. 申诉期间，不停止原处分决定的执行。\n\n**二、处分撤销/解除流程（考察期满后）**\n1. 处分考察期：警告、严重警告为6个月；记过为9个月；留校察看为12个月。\n2. 学生在考察期内无任何违纪行为，且表现良好（如获得奖学金、积极参加公益活动等），可申请解除。\n3. 填写《学生违纪处分解除申请表》，撰写个人思想汇报（不少于800字），并附考察期内获奖证明。\n4. 班级评议、辅导员签署意见 -> 学院党政联席会审议 -> 学生处审核 -> 学校主管领导批准。\n5. 处分解除后，原处分材料不再存入个人档案（除开除学籍外），取消评优评先的限制。\n\n**三、注意事项**\n1. 受处分学生应端正态度，积极改正。受处分期间再次违纪的，加重一级处分。\n2. 毕业时处分尚未解除的，暂缓发放毕业证或学位证。', NULL, '1', '', NOW(), NOW()),
(4, '关于2024年暑假期间留校学生管理及服务安排的通知', '各位同学：\n\n2024年暑假将至，为做好暑期留校学生的管理与服务工作，确保留校学生度过一个平安、充实的假期，现将有关事项通知如下：\n\n**一、留校申请**\n1. 因考研复习、实习、竞赛集训、科研任务等原因确需留校的学生，须于**6月30日前**登录“学工系统” -> “假期留校申请”模块填写申请，并上传家长知情同意书。\n2. 经辅导员、学院、学生处逐级审批通过后，方可留校。\n3. 未提交申请或未经批准的学生，暑假期间原则上不得留校住宿。\n\n**二、集中住宿安排**\n1. 为节约资源，暑假期间实行**集中住宿**。所有留校学生须服从宿管中心统一安排，搬到指定宿舍楼（男生：14号楼，女生：18号楼）。\n2. 集中搬入时间为7月10日-12日，搬回原宿舍时间为8月28日-30日。\n\n**三、食堂与商铺开放**\n1. 暑假期间开放**第二食堂**（营业时间：早餐 07:30-08:30，午餐 11:30-12:30，晚餐 17:30-18:30）。\n2. 校园超市（北区店）正常营业，营业时间调整为10:00-18:00。\n\n**四、安全与纪律**\n1. 留校学生必须严格遵守宿舍管理规定，严禁使用明火和大功率电器，严禁留宿外人。\n2. 实行**晚点名制度**：每晚22:30由楼层长统计人数，未归且失联者将上报辅导员和保卫处。\n3. 注意出行安全，外出市区的同学请结伴而行，避开偏僻路段。\n4. 如中途离校回家，须提前向辅导员报备。\n\n**五、值班与联系方式**\n- 学生处值班电话：022-1234567\n- 保卫处值班电话：022-7654321\n- 校医院值班电话：022-8888888\n\n请留校同学相互转告，合理安排学习与生活，注意劳逸结合，祝大家假期愉快！', NULL, '1', '', NOW(), NOW()),
(3, '学生个人形象与公共场所行为规范', '校园是教书育人的神圣殿堂，每一位学生都应注重个人形象与公共场合举止，展现当代大学生积极向上的精神风貌。具体规范如下：\n\n**一、仪容仪表**\n1. 着装整洁、得体、大方，不得穿睡衣、背心、拖鞋进入教学区（教室、自习室、图书馆、实验室）。\n2. 不染夸张色彩的发色（如荧光色、鲜红色等），男生不留长发（前不覆额、侧不掩耳），不剃光头。\n3. 不留长指甲，不在裸露皮肤纹身（提倡无纹身），不佩戴夸张饰品。\n4. 保持身体清洁无异味，建议健身或剧烈运动后洗澡、更换衣物后再进入公共场合。\n\n**二、公共场合行为**\n1. **教室/图书馆**：手机调至静音或震动，不得接打电话。吃零食或喝饮料不得发出声响，不得吃味道浓烈的食物（如韭菜盒子、螺蛳粉）。\n2. **食堂**：排队取餐，一人一位，不得用书包占座。倡导“光盘行动”，残渣剩菜倒入泔水桶。\n3. **公共卫生间**：文明如厕，便后冲水。卫生纸丢入纸篓，不得丢入便池（以免堵塞）。\n4. **校园道路**：男女交往行为得体，不得在公共区域搂抱亲热、卿卿我我。\n\n**三、语言文明**\n1. 提倡使用文明用语“请、谢谢、对不起、你好”。\n2. 严禁讲脏话、粗话、侮辱性言语，严禁说挖苦嘲讽的话。\n\n**四、违规劝导**\n对于违反上述规范的学生，任何人都有权提醒和劝止。对于屡教不改、态度恶劣者，学校将视情节进行通报批评。', NULL, '1', '', NOW(), NOW()),
(2, '毕业生档案转递及报到证办理指南', '毕业生档案是学生毕业前家庭情况、学习成绩、政治思想表现、身体状况的记载材料，是用人单位选拔、聘用毕业生的重要依据。毕业时务必办理档案转递手续：\n\n**一、档案转递类型与流程**\n1. **已就业（单位接收档案）**：\n   - 与用人单位签订《三方协议》，且单位具备人事档案管理权（国企、事业单位、公务员单位）。\n   - 毕业前将《接收函》或调档函交至学院。\n   - 学校于7月中旬通过EMS“高校毕业生档案专用通道”统一寄送至单位。\n2. **已就业（单位不接收档案）或未就业**：\n   - 档案转回生源地（户籍所在地）的公共就业和人才服务机构（一般为市级或区县级人才中心）。\n   - 毕业前确认生源地接收单位名称及地址，登录“智慧就业平台”填写。\n   - 学校于7月底前寄出档案。\n3. **考研/升学**：\n   - 凭录取学校的《调档函》到学院办理档案转寄。\n\n**二、报到证办理**\n1. 报到证是毕业生到就业单位报到的凭证，也是干部身份、落户、转正定级的依据。\n2. 2023年起，国家不再发放纸质《报到证》，改为电子版《就业报到证》或取消报到证。请务必关注“天津市大中专学校就业信息网”最新政策。\n3. 如有需要，可联系招生就业处开具《就业推荐表》或《在职证明》。\n\n**三、注意事项**\n1. 档案严禁个人携带，严禁私自拆封（拆封即失效，任何单位不予接收）。\n2. 毕业后三个月内，务必向档案接收单位确认档案是否已寄达。\n3. 如档案丢失或去向不明，应及时联系学校就业指导中心查询EMS底单或派发记录。', NULL, '1', '', NOW(), NOW()),
(2, '校内学术资源使用指南（知网、Web of Science、VPN）', '为支持师生教学科研，我校购买了多个国内外主流学术数据库，师生可免费使用校内IP地址访问。如需校外访问，需使用VPN。指南如下：\n\n**一、常用数据库及访问入口**\n1. **中国知网（CNKI）**：`https://www.cnki.net` 收录期刊、硕博论文、会议论文、报纸、年鉴等。\n2. **万方数据**：`https://www.wanfangdata.com.cn` 侧重于学术期刊、学位论文、专利。\n3. **Web of Science (SCI/SSCI)**：`https://www.webofscience.com` 全球权威的引文索引数据库。\n4. **IEEE Xplore**：`https://ieeexplore.ieee.org` 电子电气及计算机领域顶级文献库。\n5. **Elsevier (ScienceDirect)**：`https://www.sciencedirect.com` 收录爱思唯尔旗下期刊。\n\n**二、校内访问方法**\n1. 连接校园网（WiFi名称：`ZHIHUITONG-EDU` 或宿舍有线网络）。\n2. 直接点击图书馆网站提供的数据库链接，系统自动识别IP，无需额外付费。\n3. 下载文献前，注意查看该期刊是否被我校订购（如未订购，仅能查看摘要）。\n\n**三、校外访问方法（VPN）**\n1. 访问图书馆网站 -> “校外访问” -> “VPN客户端下载”。\n2. 安装客户端后，输入学号/工号及校园网密码登录（需在信息办开通VPN权限）。\n3. 或使用WebVPN（网页版）：`https://vpn.zhihuitong.edu.cn`，登录后即可像校内一样访问数据库。\n4. **注意**：严禁使用迅雷、IDM等多线程工具批量下载文献，否则IP会被数据库商封禁。\n\n**四、文献传递服务**\n如我校未订购某篇文献，可通过“CALIS文献传递”或“读秀学术搜索”的“图书馆文献传递”功能，提交申请后一般2个工作日内会发送到邮箱。', NULL, '1', '', NOW(), NOW()),
(4, '关于严禁在宿舍楼内吸烟及使用明火的通告', '全体住宿生：\n\n近期接到多起关于宿舍楼内吸烟及存在烟味的投诉，且烟头引发火情的安全隐患极大。为保障全体住宿生的生命财产安全，根据消防法律法规及学校安全管理规定，现就严禁在宿舍楼内吸烟及使用明火通告如下：\n\n**一、严禁范围**\n1. **严禁在宿舍房间内、阳台、楼道、卫生间、盥洗室、楼梯间等楼内任何区域吸烟。**\n2. 严禁使用蜡烛、蚊香、酒精灯、煤气罐等明火。\n3. 严禁焚烧纸张、杂物。\n\n**二、吸烟区设置**\n1. 学校在每栋宿舍楼**外**设置了专门的吸烟区（配有烟灰缸及灭火器），具体位置：\n   - 1-4号楼：南侧花坛旁\n   - 5-8号楼：北侧自行车棚对面\n   - 9-12号楼：东侧小广场\n2. 有吸烟习惯的学生请移步至室外吸烟区，吸烟后确保烟头完全熄灭，并丢入烟灰缸。\n\n**三、违规处罚**\n1. **第一次查获**：通报所在学院，辅导员约谈，责令其打扫宿舍楼内公共区域卫生一周。\n2. **第二次查获**：给予警告处分，取消当年评优评先资格，并发文通报批评。\n3. **第三次查获**：给予严重警告处分，并通知家长，取消住宿资格（需搬离宿舍，自行解决住宿）。\n4. 因吸烟或使用明火引发火情的，无论后果大小，一律给予留校察看及以上处分，并承担相应经济赔偿及法律责任。\n\n**四、监督举报**\n鼓励广大学生相互监督，发现违规吸烟或使用明火行为，可向宿管员或保卫处举报。举报一经查实，对举报人给予一定物质奖励（50元/次）。\n\n消防安全，人人有责。请各位同学珍爱生命，远离火灾隐患！', NULL, '1', '', NOW(), NOW()),
(1, '学生综合素质测评实施办法', '为全面贯彻党的教育方针，引导学生德智体美劳全面发展，特制定《学生综合素质测评实施办法》。测评结果作为奖学金评定、评优评先、推优入党、毕业鉴定等重要依据。\n\n**一、测评内容及权重**\n综合素质测评总分100分，由以下四部分构成：\n1. **思想道德素质（20分）**：包含政治态度、思想品德、集体观念、遵纪守法、诚实守信等。基准分14分，表现突出加分，违规违纪扣分（如受警告处分扣5分）。\n2. **学业成绩（55分）**：依据学年平均学分绩点（GPA）折算。\n   - 计算公式：`（个人GPA / 4.5） * 55`\n   - GPA4.0以上可得50分以上。\n3. **文体活动与社会实践（15分）**：\n   - 参加学术竞赛、文体比赛、志愿服务、社会实践、科创项目等。\n   - 国家级获奖加5分，省部级加3分，校级加1-2分，累计不超过15分。\n4. **公寓表现（10分）**：\n   - 依据宿舍卫生检查结果及遵守宿管纪律情况。\n   - 满分10分，一次不合格扣2分，违纪（晚归、使用违规电器）一次扣3分。\n\n**二、测评流程**\n1. **个人自评**：每学年9月，学生登录学工系统填写自评表，提交加分证明材料。\n2. **班级评议**：班委会和团支部组成测评小组，审核材料真实性。\n3. **辅导员审核**：辅导员结合日常记录，核定最终得分。\n4. **公示**：学院审核后在班级群、公告栏公示3天，无异议后备案。\n\n**三、结果应用**\n1. 综合测评排名在专业前10%者可申请“三好学生标兵”。\n2. 排名在专业前30%者可申请“三好学生”、“优秀学生干部”。\n3. 排名在后10%者，辅导员需进行学业预警谈话。', NULL, '1', '', NOW(), NOW()),
(2, '征兵入伍学费补偿及学籍保留流程', '为鼓励大学生投身国防事业，国家对应征入伍服义务兵役的高校学生实行学费补偿、助学贷款代偿及学籍保留政策。具体流程如下：\n\n**一、申请条件**\n1. 我校全日制在籍本科生、研究生。\n2. 政治审查、体格检查双合格，被批准入伍。\n\n**二、学费补偿/贷款代偿标准**\n1. 本科生每人每年最高**12000元**，研究生每人每年最高**16000元**。\n2. 在校期间已缴纳的学费或获得的助学贷款，国家一次性补偿或代偿。\n\n**三、办理流程（入伍前）**\n1. 登录“全国征兵网” `www.gfbzb.gov.cn`，填写《应征入伍服兵役高等学校学生国家教育资助申请表》（一式两份），打印并签字。\n2. 持《申请表》到财务处审核学费缴纳情况 -> 学生处审核资助资格 -> 校领导签字盖章。\n3. 将《申请表》及《入伍通知书》复印件交至学生处资助管理中心。\n4. 学校复核汇总后报送全国学生资助管理中心，审批通过后约3-6个月将补偿款打入学生银行卡。\n\n**四、学籍保留**\n1. 凭《入伍通知书》到教务处办理休学手续，休学原因选择“参军入伍”。\n2. 学校为其保留学籍至退伍后两年。\n3. 退伍后持《退伍证》到教务处办理复学手续，可申请转专业（限一次）。\n4. 退役大学生士兵完成本科学业后，3年内参加全国硕士研究生招生考试，初试总分加10分，同等条件下优先录取。（部分省份有专项招生计划）', NULL, '1', '', NOW(), NOW()),
(4, '关于2024级新生入学体检及军训安排的通知', '2024级新同学：\n\n欢迎加入智慧通大学！为保障你的健康和顺利开展军训工作，现将入学体检及军训安排通知如下：\n\n**一、入学体检**\n1. 时间：2024年9月2日-9月5日（按学院分批进行）。\n2. 地点：校医院（综合楼东侧）。\n3. 项目：身高体重、视力、内外科、肝功能、胸片等。\n4. 注意事项：\n   - 体检前一天清淡饮食，体检当日需抽血，请保持空腹（禁食8小时，禁水4小时）。\n   - 携带身份证及一寸免冠照片一张。\n   - 如身体有特殊情况（心脏病、哮喘、癫痫、骨折等），请提前告知医生。\n\n**二、军训安排**\n1. 时间：2024年9月6日 — 9月20日（共15天）。\n2. 地点：主校区田径场、篮球场。\n3. 内容：队列训练、军体拳、内务整理、国防教育讲座、歌咏比赛、汇报表演等。\n4. **军训服装**：学校统一招标采购，含迷彩服、短袖T恤、迷彩帽、解放鞋、腰带。费用85元/套。领取时间：9月4日-5日，地点：大学生活动中心。\n\n**三、军训纪律与要求**\n1. 全体新生必须参加军训，军训成绩记入学分（2学分）。\n2. 因身体原因不能参加剧烈运动的，须凭三甲医院诊断证明向学院申请“跟训”（参加理论学习及后勤服务）。\n3. 军训期间严格考勤，迟到、早退、旷训者按《学生违纪处分条例》处理。\n4. 注意防暑防晒，及时补充水分，如有身体不适立即报告教官和辅导员。\n\n**四、温馨提示**\n1. 准备一两双软底、透气的运动鞋垫，解放鞋底较硬。\n2. 大容量水杯（1.5L以上），可适量补充淡盐水。\n3. 做好防晒措施，防止晒伤。\n4. 不要佩戴首饰、手表，以免划伤或损坏。\n\n请同学们按时参检、参训，展现新时代大学生的昂扬斗志和良好风貌！', NULL, '1', '', NOW(), NOW());